                                <div>
                                    <h2 className="text-2xl font-bold text-slate-900">ربط السيرفر العالمي (Firebase)</h2>
                                    <p className="text-gray-500 text-sm">اجعل موقعك دولياً واحفظ البيانات بشكل دائم</p>
                                </div>
                            </div>

                            {isEmbedded ? (
                                <div className="bg-blue-50 border border-blue-200 rounded-xl p-6 text-center">
                                    <Lock size={48} className="text-blue-500 mx-auto mb-4" />
                                    <h3 className="text-xl font-bold text-blue-700 mb-2">الإعدادات مدمجة في الكود</h3>
                                    <p className="text-blue-600 mb-6">يتم التحكم في الاتصال بقاعدة البيانات عبر ملف الكود المصدري.</p>
                                </div>
