        <p>إن محاولات طمس سبتمبر، سواء عبر تغيير المناهج الدراسية، أو عبر الاحتفال بمناسبات دخيلة، أو عبر التشكيك في نزاهة الثوار الأوائل، كلها محاولات بائسة ستتحطم على صخرة الوعي اليمني. فاليماني الذي رضع حب الجمهورية مع حليب أمه، لا يمكن أن يقبل بالعودة إلى تقبيل الركب أو الخضوع لسيدٍ مزعوم، مهما طال ليل الظلم.</p>

        <h3>المعركة المستمرة: الوعي قبل البندقية</h3>
        <p>إننا اليوم نخوض الامتداد الطبيعي لمعركة سبتمبر. فالمواجهة الحالية ليست وليدة اللحظة، بل هي جولة جديدة من الصراع التاريخي بين مشروع الدولة والمواطنة، وبين مشروع الإمامة والكهنوت. وكما انتصر الآباء في الستينيات بإمكانياتهم البسيطة وإيمانهم العظيم، سينتصر الأحفاد اليوم، لأن سنن التاريخ لا تحابي الظالمين، ولأن إرادة الشعوب من إرادة الله.</p>

        <p>علينا جميعاً، كتاباً وإعلاميين ومثقفين، واجب مقدس في الحفاظ على هذا الإرث العظيم، ونقله للأجيال القادمة نقياً ناصعاً كما تركه لنا الزبيري والنعمان والموشكي وكل شهداء الفجر. علينا أن نعلم أبناءنا أن سبتمبر هو الهواء الذي نتنفسه، وهو الأرض التي نمشي عليها، وهو المستقبل الذي نحلم به.</p>

        <p>ختاماً، ستظل شعلة سبتمبر وقادة، وستظل راية الجمهورية خفاقة، وسيعلم الذين ظلموا أي منقلب ينقلبون. المجد للوطن، والخلود للشهداء، ولا نامت أعين الجبناء.</p>
        `
    }
];

// Interface for Firebase Configuration
export interface FirebaseConfig {
  apiKey: string;
  authDomain: string;
  projectId: string;
  storageBucket: string;
  messagingSenderId: string;
  appId: string;
  measurementId?: string;
}

let db: any = null;

// Initialize Firebase
const initFirebase = () => {
  if (typeof window === 'undefined') return;

  // Priority 1: Use Embedded Config (Fixes cross-domain issues)
  let config: FirebaseConfig | null = EMBEDDED_FIREBASE_CONFIG;

  // Priority 2: Use LocalStorage Config (Legacy/Dev mode)
  if (!config) {
      const configStr = localStorage.getItem(KEYS.FIREBASE_CONFIG);
      if (configStr) {
          try {
             config = JSON.parse(configStr);
          } catch (e) {
             console.error("Invalid LocalStorage Config");
          }
      }
  }

  if (config) {
    try {
      const app = initializeApp(config);
      db = getFirestore(app);
      console.log("🔥 Firebase Connected Successfully");
    } catch (e: any) {
      if (e.code === 'app/duplicate-app') {
           // If app already exists, just get Firestore
      } else {
           console.error("Firebase Init Error", e);
      }
    }
  }
};

// Initialize on load
initFirebase();

const fetchVideosFromRSS = async (channelId: string): Promise<Video[]> => {
    try {
        const rssUrl = `https://www.youtube.com/feeds/videos.xml?channel_id=${channelId}`;
        const apiUrl = `https://api.rss2json.com/v1/api.json?rss_url=${encodeURIComponent(rssUrl)}`;

        const response = await fetch(apiUrl);
        const data = await response.json();

        if (data.status === 'ok' && data.items) {
            return data.items.map((item: any) => {
                // Extract Video ID from link or guid
                const videoId = item.guid.split(':')[2] || item.link.split('v=')[1];
                return {
                    id: videoId,
                    title: item.title,
                    thumbnail: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`, // RSS thumbnail is sometimes low res
                    url: item.link,
                    views: 'مشاهدة', // RSS doesn't provide view count
                    date: new Date(item.pubDate).toLocaleDateString('ar-EG')
                };
            });
        }
        return [];
    } catch (error) {
        console.error("Failed to fetch RSS videos:", error);
        return [];
    }
};

