// Interface for Firebase Configuration
export interface FirebaseConfig {
  apiKey: string;
  authDomain: string;
  projectId: string;
  storageBucket: string;
  messagingSenderId: string;
  appId: string;
  measurementId?: string;
}

let db: any = null;

// Initialize Firebase
const initFirebase = () => {
  if (typeof window === 'undefined') return;

  // Priority 1: Use Embedded Config (Fixes cross-domain issues)
  let config: FirebaseConfig | null = null;

  // Check if EMBEDDED_FIREBASE_CONFIG has real values (not placeholders)
  if (EMBEDDED_FIREBASE_CONFIG && 
      EMBEDDED_FIREBASE_CONFIG.apiKey && 
      !EMBEDDED_FIREBASE_CONFIG.apiKey.includes("ضع_كود")) {
      config = EMBEDDED_FIREBASE_CONFIG;
  }

  // Priority 2: Use LocalStorage Config (Legacy/Dev mode)
  if (!config) {
      const configStr = localStorage.getItem(KEYS.FIREBASE_CONFIG);
      if (configStr) {
          try {
             config = JSON.parse(configStr);
          } catch (e) {
             console.error("Invalid LocalStorage Config");
          }
      }
  }

  if (config) {
    try {
      const app = initializeApp(config);
      // Try to initialize Firestore with persistent cache for better offline support
      try {
          db = initializeFirestore(app, {
              localCache: persistentLocalCache({ tabManager: persistentMultipleTabManager() })
          });
          console.log("🔥 Firebase Firestore initialized with Persistence");
      } catch (err) {
          console.warn("⚠️ Persistence init failed (possibly already initialized or not supported), falling back to standard init:", err);
          db = getFirestore(app);
      }
    } catch (e: any) {
      if (e.code === 'app/duplicate-app') {
           // If app already exists, assume db is set or try to get it
           // In modular SDK duplicate-app error usually doesn't return the app instance directly in catch,
           // but we can ignore it if we don't have a way to retrieve the existing one easily here without imports.
      } else {
           console.error("Firebase Init Error", e);
      }
    }
  } else {
      console.warn("⚠️ Firebase is not configured. App is running in Local Mode.");
  }
};

// Initialize on load
initFirebase();

const fetchVideosFromRSS = async (channelId: string): Promise<Video[]> => {
    try {
        const rssUrl = `https://www.youtube.com/feeds/videos.xml?channel_id=${channelId}`;
        const apiUrl = `https://api.rss2json.com/v1/api.json?rss_url=${encodeURIComponent(rssUrl)}`;

        const response = await fetch(apiUrl);
        const data = await response.json();

        if (data.status === 'ok' && data.items) {
            return data.items.map((item: any) => {
                // Extract Video ID from link or guid
                const videoId = item.guid.split(':')[2] || item.link.split('v=')[1];
                return {
                    id: videoId,
                    title: item.title,
                    thumbnail: `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`, // RSS thumbnail is sometimes low res
                    url: item.link,
                    views: 'مشاهدة', // RSS doesn't provide view count
                    date: new Date(item.pubDate).toLocaleDateString('ar-EG')
                };
            });
        }
        return [];
    } catch (error) {
        console.error("Failed to fetch RSS videos:", error);
        return [];
    }
};

const handleFirebaseError = (e: any, context: string) => {
    if (e?.message?.includes('offline') || e?.code === 'unavailable') {
        console.warn(`[${context}] Firebase client is offline. Using local fallback.`);
    } else {
        console.error(`[${context}] Firebase Error:`, e);
    }
};

