                                                {momentImage ? <img src={momentImage} alt="Preview" className="max-h-40 rounded shadow" /> : <><ImageIcon className="w-12 h-12 text-gold-400" /><span className="text-sm text-gray-500">اضغط لرفع صورة</span></>}
                                            </label>
                                        </div>
                                        <div>
