import React, { useState, useRef, useEffect } from 'react';
import { Section, GalleryImage } from '../types';
import { Maximize2, X, Download } from 'lucide-react';

interface GallerySectionProps {
    images: GalleryImage[];
}

const GallerySection: React.FC<GallerySectionProps> = ({ images }) => {
    const [selectedImage, setSelectedImage] = useState<GalleryImage | null>(null);
    const scrollRef = useRef<HTMLDivElement>(null);
    const [isDragging, setIsDragging] = useState(false);
    const [startX, setStartX] = useState(0);
    const [scrollLeft, setScrollLeft] = useState(0);

    // Triple images to ensure a truly seamless manual and auto loop
    const displayImages = [...images, ...images, ...images];

    useEffect(() => {
        const slider = scrollRef.current;
        if (!slider || images.length === 0) return;

        // Start from the middle clone to allow scrolling in both directions immediately
        const scrollWidth = slider.scrollWidth;
        slider.scrollLeft = -scrollWidth / 3;

        let animationFrameId: number;
        const speed = 0.5; // Pixels per frame

        const step = () => {
            if (!isDragging) {
                // In RTL, scrollLeft is negative or decreasing
                slider.scrollLeft -= speed;

                // Infinite loop logic: when reaching far left or right, jump back to middle
                const maxScroll = slider.scrollWidth / 3;
                if (Math.abs(slider.scrollLeft) >= maxScroll * 2) {
                    slider.scrollLeft = -maxScroll;
                } else if (slider.scrollLeft >= 0) {
                    slider.scrollLeft = -maxScroll;
                }
            }
            animationFrameId = requestAnimationFrame(step);
        };

        animationFrameId = requestAnimationFrame(step);
        return () => cancelAnimationFrame(animationFrameId);
    }, [images.length, isDragging]);

    // Manual Drag Handlers
    const handleMouseDown = (e: React.MouseEvent) => {
        setIsDragging(true);
        setStartX(e.pageX - (scrollRef.current?.offsetLeft || 0));
        setScrollLeft(scrollRef.current?.scrollLeft || 0);
    };

    const handleMouseLeave = () => setIsDragging(false);
    const handleMouseUp = () => setIsDragging(false);

    const handleMouseMove = (e: React.MouseEvent) => {
